// Some portions generated by Co-Pilot
/**
 * Build-time script to generate a Pagefind search index from AsciiDoc docs.
 *
 * Uses Pagefind's Node API to add each document as a custom record,
 * then writes the search index bundle to public/pagefind/ so it can
 * be served as static assets.
 *
 * Runs automatically via the `postbuild` npm script.
 */

import fs from "fs";
import path from "path";
import { fileURLToPath } from "url";
import { createRequire } from "module";

const require = createRequire(import.meta.url);
const __dirname = path.dirname(fileURLToPath(import.meta.url));
const ROOT = path.resolve(__dirname, "..");
const CONTENT_BASE_DIR = path.join(ROOT, "content/asciidoc-pages");
const OUTPUT_DIR = path.join(ROOT, "public/pagefind");

function getAllDocs() {
  const Asciidoctor = require("@asciidoctor/core")();
  const docs = [];

  function traverse(dir, currentPath = []) {
    const entries = fs.readdirSync(dir, { withFileTypes: true });

    for (const entry of entries) {
      if (entry.isDirectory() && entry.name !== "_partials") {
        traverse(path.join(dir, entry.name), [...currentPath, entry.name]);
      } else if (entry.isFile() && entry.name.endsWith(".adoc")) {
        const match = entry.name.match(/^index(?:\.([a-zA-Z0-9_-]+))?\.adoc$/);
        if (!match) continue;

        const locale = match[1] || "en";
        // Only index English pages — search is English-only for now
        if (locale !== "en") continue;
        const slug = currentPath.join("/");
        const filePath = path.join(dir, entry.name);
        const rawContent = fs.readFileSync(filePath, "utf8");

        const doc = Asciidoctor.load(rawContent, {
          safe: "server",
          base_dir: path.dirname(filePath),
        });
        // Decode HTML entities in the title (e.g. &#8482; → ™)
        const rawTitle = doc.getDocumentTitle()?.toString() || slug;
        const title = rawTitle.replace(/&#(\d+);/g, (_, code) =>
          String.fromCodePoint(Number(code)),
        );
        const description = doc.hasAttribute("description")
          ? String(doc.getAttribute("description"))
          : "";

        // Convert to HTML for full-text indexing, stripping tags for plain text
        const html = Asciidoctor.convert(rawContent, {
          safe: "server",
          base_dir: path.dirname(filePath),
        });
        const plainText = html
          .replace(/<[^>]+>/g, " ")
          .replace(/\s+/g, " ")
          .trim();

        docs.push({
          title,
          description,
          slug,
          locale,
          section: currentPath[0] || "",
          content: plainText,
        });
      }
    }
  }

  traverse(CONTENT_BASE_DIR);
  return docs;
}

async function main() {
  const pagefind = await import("pagefind");
  const { index } = await pagefind.createIndex({});
  if (!index) {
    console.error("Failed to create Pagefind index");
    process.exit(1);
  }

  const docs = getAllDocs();
  console.log(`Indexing ${docs.length} documents...`);

  for (const doc of docs) {
    // Build a synthetic HTML page for Pagefind to index
    const html = `<!DOCTYPE html>
<html lang="${doc.locale}">
<head><title>${doc.title}</title></head>
<body>
<h1>${doc.title}</h1>
<p>${doc.description}</p>
<div>${doc.content}</div>
</body>
</html>`;

    await index.addHTMLFile({
      url: `/${doc.slug}`,
      content: html,
    });
  }

  // Write the search index to public/pagefind/
  await index.writeFiles({ outputPath: OUTPUT_DIR });
  console.log(`Pagefind index written to ${OUTPUT_DIR}`);

  await pagefind.close();
}

main().catch((err) => {
  console.error("Indexing failed:", err);
  process.exit(1);
});
